using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: Cosmos DB indexes are no longer managed by EF Core 9.
        // HasIndex() now throws. Remove it; manage indexes via Azure portal or IaC.
        // modelBuilder.Entity<Blog>().HasIndex(b => b.Name);  // REMOVED

        // Breaking change 2: Discriminator property renamed from "Discriminator" to "$type".
        // To stay compatible with existing documents, explicitly keep the old property name.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 3: Id format changed from "EntityName|<key>" to just "<key>".
        // To read existing "Blog|1"-style ids, opt back into the legacy format.
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>(b =>
        {
            b.Property(e => e.Id)
             .ToJsonProperty("id")
             .HasValueGenerator<LegacyCosmosIdGenerator>();
        });
    }

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        // Breaking change 4: Sync I/O now throws by default in EF Core 9.
        // Fix: either switch to async APIs (preferred) or opt-in to sync I/O.
        // We enable sync here so SyncJob.Run() keeps working without rewrite.
        // Prefer migrating to async long-term.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; }  }

// Value generator that reproduces the EF8 "EntityType|KeyValue" id format
// so existing Cosmos documents remain addressable.
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
        => $"{entry.Metadata.ShortName()}|{entry.Property("Id").CurrentValue}";
}

