toolArgs.new_str:
using Microsoft.EntityFrameworkCore;

class SyncJob
{
    // BREAKING CHANGE 4 – Sync I/O now throws by default in the Cosmos provider.
    // Fix: convert to async. (Alternative: call options.EnableSyncIO() on the
    // DbContextOptionsBuilder, but async is strongly preferred.)
    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();
    }
}

